import React, { useState } from "react";

const SendEmailPage = () => {
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState("");

  const sendEmail = async (event = "custom") => {
    setLoading(true);
    setStatus("");

    const token = JSON.parse(localStorage.getItem("userInfo"))?.token;

    const res = await fetch("http://localhost:5000/api/email/send", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ event }),
    });

    const data = await res.json();
    setLoading(false);

    if (data.success) setStatus("📨 Email đã gửi thành công!");
    else setStatus("❌ Gửi email thất bại!");
  };

  return (
    <div className="p-8">
      <h2 className="text-2xl font-bold text-[#e06c7f] mb-5">
        📩 Gửi Email Khuyến Mãi
      </h2>

      <button
        onClick={() => sendEmail("valentine")}
        className="bg-[#e06c7f] text-white px-4 py-3 rounded-lg hover:bg-[#d35d75]"
      >
        Gửi email Valentine 💘
      </button>

      {status && <p className="mt-4 text-lg">{status}</p>}
    </div>
  );
};

export default SendEmailPage;
